// Dentro de tu función handleLogin en Login.js:
const handleLogin = (e) => {
  e.preventDefault();
  
  // 1. Guardar datos
  localStorage.setItem('token-falso', 'token-123');
  localStorage.setItem('user-role', role);
  
  // 2. Actualizar App.js
  setIsLoggedIn(true);
  setUserRole(role);
  
  // 3. Pequeño delay o ejecución inmediata para asegurar que el estado "subió" a App.js
  setTimeout(() => {
    if (role === 'vendedor') {
      navigate('/dashboard', { replace: true });
    } else {
      navigate('/', { replace: true });
    }
  }, 10);
};
